 43→
 44→#define	LIGHTING_CACHE_SIZE	4096	//	Must be power of 2!
 45→#define	LIGHTING_FRAME_DELTA	256	//	Recompute cache value every 8 frames.
 46→#define	LIGHTING_CACHE_SHIFT	8
 47→
 48→int	Lighting_frame_delta = 1;
 49→
 50→int	Lighting_cache[LIGHTING_CACHE_SIZE];
 51→
 52→int Cache_hits = 0, Cache_lookups = 1;
 53→
 54→//	Return true if we think vertex vertnum is visible from segment segnum.
 55→//	If some amount of time has gone by, then recompute, else use cached value.
 56→int lighting_cache_visible(int vertnum, int segnum, int objnum, vms_vector* obj_pos, int obj_seg, vms_vector* vertpos)
 57→{
 58→#ifdef USE_OX_BRIDGE
 59→	{
 60→		int cache_index = ((segnum << LIGHTING_CACHE_SHIFT) ^ vertnum) & (LIGHTING_CACHE_SIZE - 1);
 61→		int32_t packed[13];
 62→		packed[0] = vertnum;
 63→		packed[1] = segnum;
 64→		packed[2] = objnum;
 65→		packed[3] = obj_pos->x;
 66→		packed[4] = obj_pos->y;
 67→		packed[5] = obj_pos->z;
 68→		packed[6] = obj_seg;
 69→		packed[7] = vertpos->x;
 70→		packed[8] = vertpos->y;
 71→		packed[9] = vertpos->z;
 72→		packed[10] = FrameCount;
 73→		packed[11] = Lighting_frame_delta;
 74→		packed[12] = Lighting_cache[cache_index];
 75→		int32_t out[3];
 76→		cd_ox_lighting_cache_visible(packed, 13, out);
 77→		int apply_light = out[0];
 78→		int new_cache_val = out[1];
 79→		int cache_hit = out[2];
 80→		Cache_lookups++;
 81→		if (cache_hit)
 82→			Cache_hits++;
 83→		if (new_cache_val != -1)
 84→			Lighting_cache[cache_index] = new_cache_val;
 85→		return apply_light;
 86→	}
 87→#endif
 88→	int	cache_val, cache_frame, cache_vis;
 89→
 90→	cache_val = Lighting_cache[((segnum << LIGHTING_CACHE_SHIFT) ^ vertnum) & (LIGHTING_CACHE_SIZE - 1)];
 91→
 92→	cache_frame = cache_val >> 1;
 93→	cache_vis = cache_val & 1;
 94→
 95→	//mprintf((0, "%i %i %5i %i ", vertnum, segnum, cache_frame, cache_vis));
 96→
 97→	Cache_lookups++;
 98→	if ((cache_frame == 0) || (cache_frame + Lighting_frame_delta <= FrameCount))
 99→	{
100→		int			apply_light = 0;
101→		fvi_query	fq;
102→		fvi_info		hit_data;
103→		int			segnum, hit_type;
104→
105→#ifndef NDEBUG
106→		segnum = find_point_seg(obj_pos, obj_seg);
107→		if (segnum == -1) {
108→			Int3();		//	Obj_pos is not in obj_seg!
109→			return 0;		//	Done processing this object.
110→		}
111→#endif
112→
113→		fq.p0 = obj_pos;
114→		fq.startseg = obj_seg;
115→		fq.p1 = vertpos;
116→		fq.rad = 0;
117→		fq.thisobjnum = objnum;
118→		fq.ignore_obj_list = NULL;
119→		fq.flags = FQ_TRANSWALL;
120→
121→		hit_type = find_vector_intersection(&fq, &hit_data);
122→
123→		// Hit_pos = Hit_data.hit_pnt;
124→		// Hit_seg = Hit_data.hit_seg;
125→
126→		if (hit_type == HIT_OBJECT)
127→			Int3();	//	Hey, we're not supposed to be checking objects!
128→
129→		if (hit_type == HIT_NONE)
130→			apply_light = 1;
131→		else if (hit_type == HIT_WALL)
132→		{
133→			fix	dist_dist;
134→			dist_dist = vm_vec_dist_quick(&hit_data.hit_pnt, obj_pos);
135→			if (dist_dist < F1_0 / 4)
136→			{
137→				apply_light = 1;
138→				// -- Int3();	//	Curious, did fvi detect intersection with wall containing vertex?
139→			}
140→		}
141→		Lighting_cache[((segnum << LIGHTING_CACHE_SHIFT) ^ vertnum) & (LIGHTING_CACHE_SIZE - 1)] = apply_light + (FrameCount << 1);
142→		//mprintf((0, "%i\n", apply_light));
143→		return apply_light;
144→	}
145→	else
146→	{
147→		//mprintf((0, "\n"));
148→		Cache_hits++;
149→		return cache_vis;
150→	}
151→}
