156→// ----------------------------------------------------------------------------------------------
157→void apply_light(fix obj_intensity, int obj_seg, vms_vector* obj_pos, int n_render_vertices, short* render_vertices, int objnum)
158→{
159→	int	vv;
160→
161→	if (obj_intensity)
162→	{
163→		fix	obji_64 = obj_intensity * 64;
164→
165→		// for pretty dim sources, only process vertices in object's own segment.
166→		//	12/04/95, MK, markers only cast light in own segment.
167→		if ((abs(obji_64) <= F1_0 * 8) || (Objects[objnum].type == OBJ_MARKER))
168→		{
169→			short* vp = Segments[obj_seg].verts;
170→
171→			for (vv = 0; vv < MAX_VERTICES_PER_SEGMENT; vv++)
172→			{
173→				int			vertnum;
174→				vms_vector* vertpos;
175→				fix			dist;
176→
177→				vertnum = vp[vv];
178→				if ((vertnum ^ FrameCount) & 1)
179→				{
180→					vertpos = &Vertices[vertnum];
181→					dist = vm_vec_dist_quick(obj_pos, vertpos);
182→					dist = fixmul(dist / 4, dist / 4);
183→					if (dist < abs(obji_64)) {
184→						if (dist < MIN_LIGHT_DIST)
185→							dist = MIN_LIGHT_DIST;
186→
187→						Dynamic_light[vertnum] += fixdiv(obj_intensity, dist);
188→					}
189→				}
190→			}
191→		}
192→		else
193→		{
194→			int	headlight_shift = 0;
195→			fix	max_headlight_dist = F1_0 * 200;
196→
197→			if (CurrentLogicVersion >= LogicVer::FULL_1_0)
198→			{
199→				if (Objects[objnum].type == OBJ_PLAYER)
200→					if (Players[Objects[objnum].id].flags & PLAYER_FLAGS_HEADLIGHT_ON)
201→					{
202→						headlight_shift = 3;
203→						if (Objects[objnum].id != Player_num)
204→						{
205→							vms_vector	tvec;
206→							fvi_query	fq;
207→							fvi_info		hit_data;
208→							int			fate;
209→
210→							vm_vec_scale_add(&tvec, &Objects[objnum].pos, &Objects[objnum].orient.fvec, F1_0 * 200);
211→
212→							fq.startseg = Objects[objnum].segnum;
213→							fq.p0 = &Objects[objnum].pos;
214→							fq.p1 = &tvec;
215→							fq.rad = 0;
216→							fq.thisobjnum = objnum;
217→							fq.ignore_obj_list = NULL;
218→							fq.flags = FQ_TRANSWALL;
219→
220→							fate = find_vector_intersection(&fq, &hit_data);
221→							if (fate != HIT_NONE)
222→								max_headlight_dist = vm_vec_mag_quick(vm_vec_sub(&tvec, &hit_data.hit_pnt, &Objects[objnum].pos)) + F1_0 * 4;
223→						}
224→					}
225→
226→
227→				// -- for (vv=FrameCount&1; vv<n_render_vertices; vv+=2) {
228→				for (vv = 0; vv < n_render_vertices; vv++)
229→				{
230→					int			vertnum;
231→					vms_vector* vertpos;
232→					fix			dist;
233→					int			apply_light;
234→
235→					vertnum = render_vertices[vv];
236→					if ((vertnum ^ FrameCount) & 1)
237→					{
238→						vertpos = &Vertices[vertnum];
239→						dist = vm_vec_dist_quick(obj_pos, vertpos);
240→						apply_light = 0;
241→
242→						if ((dist >> headlight_shift) < abs(obji_64))
243→						{
244→							if (dist < MIN_LIGHT_DIST)
245→								dist = MIN_LIGHT_DIST;
246→
247→							//if (Use_fvi_lighting) {
248→							//	if (lighting_cache_visible(vertnum, obj_seg, objnum, obj_pos, obj_seg, vertpos)) {
249→							//		apply_light = 1;
250→							//	}
251→							//} else
252→							apply_light = 1;
253→
254→							if (apply_light)
255→							{
256→								if (headlight_shift)
257→								{
258→									fix			dot;
259→									vms_vector	vec_to_point;
260→
261→									vm_vec_sub(&vec_to_point, vertpos, obj_pos);
262→									vm_vec_normalize_quick(&vec_to_point);		//	MK, Optimization note: You compute distance about 15 lines up, this is partially redundant
263→									dot = vm_vec_dot(&vec_to_point, &Objects[objnum].orient.fvec);
264→									if (dot < F1_0 / 2)
265→										Dynamic_light[vertnum] += fixdiv(obj_intensity, fixmul(HEADLIGHT_SCALE, dist));	//	Do the normal thing, but darken around headlight.
266→									else
267→									{
268→										if (Game_mode & GM_MULTI)
269→										{
270→											if (dist < max_headlight_dist)
271→												Dynamic_light[vertnum] += fixmul(fixmul(dot, dot), obj_intensity) / 8;
272→										}
273→										else
274→											Dynamic_light[vertnum] += fixmul(fixmul(dot, dot), obj_intensity) / 8;
275→									}
276→								}
277→								else
278→									Dynamic_light[vertnum] += fixdiv(obj_intensity, dist);
279→							}
280→						}
281→					}
282→				}
283→			}
284→			else
285→			{
286→				for (vv = FrameCount & 1; vv < n_render_vertices; vv += 2) 
287→				{
288→					int			vertnum;
289→					vms_vector* vertpos;
290→					fix			dist;
291→
292→					vertnum = render_vertices[vv];
293→					vertpos = &Vertices[vertnum];
294→					dist = vm_vec_dist_quick(obj_pos, vertpos);
295→
296→					if (dist < obji_64) 
297→					{
298→						if (dist < MIN_LIGHT_DIST)
299→							dist = MIN_LIGHT_DIST;
300→
301→						Dynamic_light[vertnum] += fixdiv(obj_intensity, dist);
302→					}
303→				}
304→			}
305→		}
306→	}
307→}
