309→#define	FLASH_LEN_FIXED_SECONDS	(F1_0/3)
310→#define	FLASH_SCALE					(3*F1_0/FLASH_LEN_FIXED_SECONDS)
311→
312→// ----------------------------------------------------------------------------------------------
313→void cast_muzzle_flash_light(int n_render_vertices, short* render_vertices)
314→{
315→	fix current_time;
316→	int	i;
317→	short	time_since_flash;
318→
319→	current_time = timer_get_fixed_seconds();
320→
321→	for (i = 0; i < MUZZLE_QUEUE_MAX; i++)
322→	{
323→		if (Muzzle_data[i].create_time)
324→		{
325→			time_since_flash = current_time - Muzzle_data[i].create_time;
326→			if (time_since_flash < FLASH_LEN_FIXED_SECONDS)
327→				apply_light((FLASH_LEN_FIXED_SECONDS - time_since_flash) * FLASH_SCALE, Muzzle_data[i].segnum, &Muzzle_data[i].pos, n_render_vertices, render_vertices, -1);
328→			else
329→				Muzzle_data[i].create_time = 0;		// turn off this muzzle flash
330→		}
331→	}
332→}
333→
334→//	Translation table to make flares flicker at different rates
335→fix	Obj_light_xlate[16] =
336→{ 0x1234, 0x3321, 0x2468, 0x1735,
337→ 0x0123, 0x19af, 0x3f03, 0x232a,
338→ 0x2123, 0x39af, 0x0f03, 0x132a,
339→ 0x3123, 0x29af, 0x1f03, 0x032a };
340→
341→//	Flag array of objects lit last frame.  Guaranteed to process this frame if lit last frame.
342→int8_t Lighting_objects[MAX_OBJECTS];
343→
344→#define	MAX_HEADLIGHTS	8
345→object * Headlights[MAX_HEADLIGHTS];
346→int		Num_headlights;
347→
348→// ---------------------------------------------------------
349→fix compute_light_intensity(int objnum)
350→{
351→	object* obj = &Objects[objnum];
352→	int			objtype = obj->type;
353→	fix hoardlight, s;
354→
355→	switch (objtype) {
356→	case OBJ_PLAYER:
357→		if (CurrentLogicVersion >= LogicVer::FULL_1_0)
358→		{
359→			if (Players[obj->id].flags & PLAYER_FLAGS_HEADLIGHT_ON)
360→			{
361→				if (Num_headlights < MAX_HEADLIGHTS)
362→					Headlights[Num_headlights++] = obj;
363→				return HEADLIGHT_SCALE;
364→			}
365→			else if ((Game_mode & GM_HOARD) && Players[obj->id].secondary_ammo[PROXIMITY_INDEX])
366→			{
367→
368→				// If hoard game and player, add extra light based on how many orbs you have
369→				 // Pulse as well.
370→
371→				hoardlight = i2f(Players[obj->id].secondary_ammo[PROXIMITY_INDEX]) / 2; //i2f(12));
372→				hoardlight++;
373→				fix_sincos((GameTime / 2) & 0xFFFF, &s, NULL); // probably a bad way to do it
374→				s += F1_0;
375→				s >>= 1;
376→				hoardlight = fixmul(s, hoardlight);
377→				//     mprintf ((0,"Hoardlight is %f!\n",f2fl(hoardlight)));
378→				return (hoardlight);
379→			}
380→			else
381→				return std::max(vm_vec_mag_quick(&obj->mtype.phys_info.thrust) / 4, (fix)F1_0 * 2) + F1_0 / 2;
382→		}
383→		else 
384→		{
385→			if (obj->id != Player_num)
386→			{
387→				if (Players[obj->id].flags & PLAYER_FLAGS_HEADLIGHT_ON)
388→					return F1_0 * 4;
389→				else
390→					return F1_0 / 2;
391→			}
392→			else //replicate incredibly strange bug from the demo, making lighting brighter than expected. 
393→			{
394→				if (obj->id != 0xff)
395→				{
396→					if (obj->lifeleft < F1_0 * 4)
397→						return fixmul(fixdiv(obj->lifeleft, Vclip[obj->id].play_time), Vclip[obj->id].light_value);
398→					else
399→						return Vclip[obj->id].light_value;
400→				}
401→			}
402→		}
403→		return 0;
404→	case OBJ_FIREBALL:
405→		if (obj->id != 0xff)
406→		{
407→			if (obj->lifeleft < F1_0 * 4)
408→				return fixmul(fixdiv(obj->lifeleft, Vclip[obj->id].play_time), Vclip[obj->id].light_value);
409→			else
410→				return Vclip[obj->id].light_value;
411→		}
412→		else
413→			return 0;
414→		break;
415→	case OBJ_ROBOT:
416→		return F1_0 * Robot_info[obj->id].lightcast;
417→		break;
418→	case OBJ_WEAPON:
419→	{
420→		fix tval = Weapon_info[obj->id].light;
421→		if (Game_mode & GM_MULTI)
422→			if (obj->id == OMEGA_ID)
423→				if (P_Rand() > 8192)
424→					return 0;		//	3/4 of time, omega blobs will cast 0 light!
425→
426→		if (obj->id == FLARE_ID)
427→			return 2 * (std::min(tval, obj->lifeleft) + ((GameTime ^ Obj_light_xlate[objnum & 0x0f]) & 0x3fff));
428→		else
429→			return tval;
430→	}
431→
432→	case OBJ_MARKER:
433→	{
434→		fix	lightval = obj->lifeleft;
435→
436→		lightval &= 0xffff;
437→
438→		lightval = 8 * abs(F1_0 / 2 - lightval);
439→
440→		if (obj->lifeleft < F1_0 * 1000)
441→			obj->lifeleft += F1_0;	//	Make sure this object doesn't go out.
442→
443→		return lightval;
444→	}
445→
446→	case OBJ_POWERUP:
447→		return Powerup_info[obj->id].light;
448→		break;
449→	case OBJ_DEBRIS:
450→		return F1_0 / 4;
451→		break;
452→	case OBJ_LIGHT:
453→		return obj->ctype.light_info.intensity;
454→		break;
455→	default:
456→		return 0;
457→		break;
458→	}
459→}
