461→// ----------------------------------------------------------------------------------------------
462→void set_dynamic_light(void)
463→{
464→	int	vv;
465→	int	objnum;
466→	int	n_render_vertices;
467→	short	render_vertices[MAX_VERTICES];
468→	int8_t	render_vertex_flags[MAX_VERTICES];
469→	int	render_seg, segnum, v;
470→	int8_t	new_lighting_objects[MAX_OBJECTS];
471→
472→	Num_headlights = 0;
473→
474→	if (!Do_dynamic_light)
475→		return;
476→
477→	//if (Use_fvi_lighting)
478→	//	mprintf((0, "hits = %8i, misses = %8i, lookups = %8i, hit ratio = %7.4f\n", Cache_hits, Cache_lookups - Cache_hits, Cache_lookups, (float) Cache_hits / Cache_lookups));
479→
480→	memset(render_vertex_flags, 0, Highest_vertex_index + 1);
481→
482→	//	Create list of vertices that need to be looked at for setting of ambient light.
483→	n_render_vertices = 0;
484→	for (render_seg = 0; render_seg < N_render_segs; render_seg++)
485→	{
486→		segnum = Render_list[render_seg];
487→		if (segnum != -1)
488→		{
489→			short* vp = Segments[segnum].verts;
490→			for (v = 0; v < MAX_VERTICES_PER_SEGMENT; v++)
491→			{
492→				int	vnum = vp[v];
493→				if (vnum<0 || vnum>Highest_vertex_index)
494→				{
495→					Int3();		//invalid vertex number
496→					continue;	//ignore it, and go on to next one
497→				}
498→				if (!render_vertex_flags[vnum])
499→				{
500→					render_vertex_flags[vnum] = 1;
501→					render_vertices[n_render_vertices++] = vnum;
502→				}
503→			}
504→		}
505→	}
506→
507→	if (CurrentLogicVersion >= LogicVer::FULL_1_0)
508→	{
509→		for (vv = 0; vv < n_render_vertices; vv++)
510→		{
511→			int	vertnum;
512→
513→			vertnum = render_vertices[vv];
514→			Assert(vertnum >= 0 && vertnum <= Highest_vertex_index);
515→			if ((vertnum ^ FrameCount) & 1)
516→				Dynamic_light[vertnum] = 0;
517→		}
518→	}
519→	else
520→	{
521→		for (vv = FrameCount & 1; vv < n_render_vertices; vv += 2) 
522→		{
523→			Assert(render_vertices[vv] >= 0 && render_vertices[vv] <= Highest_vertex_index);
524→			Dynamic_light[render_vertices[vv]] = 0;
525→		}
526→	}
527→
528→	cast_muzzle_flash_light(n_render_vertices, render_vertices);
529→
530→	for (objnum = 0; objnum <= Highest_object_index; objnum++)
531→		new_lighting_objects[objnum] = 0;
532→
533→	//	July 5, 1995: New faster dynamic lighting code.  About 5% faster on the PC (un-optimized).
534→	//	Only objects which are in rendered segments cast dynamic light.  We might wad6 to extend this
535→	//	one or two segments if we notice light changing as objects go offscreen.  I couldn't see any
536→	//	serious visual degradation.  In fact, I could see no humorous degradation, either. --MK
537→	for (render_seg = 0; render_seg < N_render_segs; render_seg++)
538→	{
539→		int	segnum = Render_list[render_seg];
540→
541→		objnum = Segments[segnum].objects;
542→
543→		while (objnum != -1)
544→		{
545→			object* obj = &Objects[objnum];
546→			vms_vector* objpos = &obj->pos;
547→			fix			obj_intensity;
548→
549→			obj_intensity = compute_light_intensity(objnum);
550→
551→			if (obj_intensity)
552→			{
553→				apply_light(obj_intensity, obj->segnum, objpos, n_render_vertices, render_vertices, obj - Objects);
554→				new_lighting_objects[objnum] = 1;
555→			}
556→
557→			objnum = obj->next;
558→		}
559→	}
560→
561→	//	Now, process all lights from last frame which haven't been processed this frame.
562→	for (objnum = 0; objnum <= Highest_object_index; objnum++)
563→	{
564→		//	In multiplayer games, process even unprocessed objects every 4th frame, else don't know about player sneaking up.
565→		if ((Lighting_objects[objnum]) || ((Game_mode & GM_MULTI) && (((objnum ^ FrameCount) & 3) == 0)))
566→		{
567→			if (!new_lighting_objects[objnum])
568→			{
569→				//	Lighted last frame, but not this frame.  Get intensity...
570→				object* obj = &Objects[objnum];
571→				vms_vector* objpos = &obj->pos;
572→				fix			obj_intensity;
573→
574→				obj_intensity = compute_light_intensity(objnum);
575→
576→				if (obj_intensity)
577→				{
578→					apply_light(obj_intensity, obj->segnum, objpos, n_render_vertices, render_vertices, objnum);
579→					Lighting_objects[objnum] = 1;
580→				}
581→				else
582→					Lighting_objects[objnum] = 0;
583→			}
584→		}
585→		else
586→		{
587→			//	Not lighted last frame, so we don't need to light it.  (Already lit if casting light this frame.)
588→			//	But copy value from new_lighting_objects to update Lighting_objects array.
589→			Lighting_objects[objnum] = new_lighting_objects[objnum];
590→		}
591→	}
592→}
593→
594→// ---------------------------------------------------------
595→
596→void toggle_headlight_active()
597→{
598→	if (Players[Player_num].flags & PLAYER_FLAGS_HEADLIGHT)
599→	{
600→		Players[Player_num].flags ^= PLAYER_FLAGS_HEADLIGHT_ON;
601→#ifdef NETWORK
602→		if (Game_mode & GM_MULTI)
603→			multi_send_flags(Player_num);
604→#endif
605→	}
606→}
607→
608→#define HEADLIGHT_BOOST_SCALE 8		//how much to scale light when have headlight boost
609→
610→fix	Beam_brightness = (F1_0 / 2);	//global saying how bright the light beam is
611→
612→#define MAX_DIST_LOG	6							//log(MAX_DIST-expressed-as-integer)
613→#define MAX_DIST		(f1_0<<MAX_DIST_LOG)	//no light beyond this dist
614→
615→fix compute_headlight_light_on_object(object * objp)
616→{
617→	int	i;
618→	fix	light;
619→
620→	//	Let's just illuminate players and robots for speed reasons, ok?
621→	if ((objp->type != OBJ_ROBOT) && (objp->type != OBJ_PLAYER))
622→		return 0;
623→
624→	light = 0;
625→
626→	for (i = 0; i < Num_headlights; i++)
627→	{
628→		fix			dot, dist;
629→		vms_vector	vec_to_obj;
630→		object* light_objp;
631→
632→		light_objp = Headlights[i];
633→
634→		vm_vec_sub(&vec_to_obj, &objp->pos, &light_objp->pos);
635→		dist = vm_vec_normalize_quick(&vec_to_obj);
636→		if (dist > 0)
637→		{
638→			dot = vm_vec_dot(&light_objp->orient.fvec, &vec_to_obj);
639→
640→			if (dot < F1_0 / 2)
641→				light += fixdiv(HEADLIGHT_SCALE, fixmul(HEADLIGHT_SCALE, dist));	//	Do the normal thing, but darken around headlight.
642→			else
643→				light += fixmul(fixmul(dot, dot), HEADLIGHT_SCALE) / 8;
644→		}
645→	}
646→
647→	return light;
648→}
649→
650→//compute the average dynamic light in a segment.  Takes the segment number
651→fix compute_seg_dynamic_light(int segnum)
652→{
653→	fix sum;
654→	segment* seg;
655→	short* verts;
656→
657→	seg = &Segments[segnum];
658→
659→	verts = seg->verts;
660→	sum = 0;
661→
662→	sum += Dynamic_light[*verts++];
663→	sum += Dynamic_light[*verts++];
664→	sum += Dynamic_light[*verts++];
665→	sum += Dynamic_light[*verts++];
666→	sum += Dynamic_light[*verts++];
667→	sum += Dynamic_light[*verts++];
668→	sum += Dynamic_light[*verts++];
669→	sum += Dynamic_light[*verts];
670→
671→	return sum >> 3;
672→}
673→
674→fix object_light[MAX_OBJECTS];
675→int object_sig[MAX_OBJECTS];
676→object* old_viewer;
677→int reset_lighting_hack;
678→
679→#define LIGHT_RATE i2f(4)		//how fast the light ramps up
680→
681→void start_lighting_frame(object* viewer)
682→{
683→	reset_lighting_hack = (viewer != old_viewer);
684→	old_viewer = viewer;
685→}
686→
687→//compute the lighting for an object.  Takes a pointer to the object,
688→//and possibly a rotated 3d point.  If the point isn't specified, the
689→//object's center point is rotated.
690→fix compute_object_light(object* obj, vms_vector* rotated_pnt)
691→{
692→#ifdef USE_OX_BRIDGE
693→	int objnum = obj - Objects;
694→	g3s_point objpnt;
695→	if (!rotated_pnt) {
696→		g3_rotate_point(&objpnt, &obj->pos);
697→		rotated_pnt = &objpnt.p3_vec;
698→	}
699→	fix headlight_contrib;
700→	if (CurrentLogicVersion >= LogicVer::FULL_1_0)
701→		headlight_contrib = compute_headlight_light_on_object(obj);
702→	else
703→		headlight_contrib = compute_headlight_light(rotated_pnt, f1_0);
704→	int32_t packed[8];
705→	packed[0] = Segment2s[obj->segnum].static_light;
706→	packed[1] = object_light[objnum];
707→	packed[2] = object_sig[objnum];
708→	packed[3] = obj->signature;
709→	packed[4] = FrameTime;
710→	packed[5] = reset_lighting_hack ? 1 : 0;
711→	packed[6] = headlight_contrib;
712→	packed[7] = compute_seg_dynamic_light(obj->segnum);
713→	int32_t out[2];
714→	cd_ox_compute_object_light(packed, 8, out);
715→	object_light[objnum] = out[1];
716→	object_sig[objnum] = obj->signature;
717→	return out[0];
718→#else
719→	fix light;
720→	g3s_point objpnt;
721→	int objnum = obj - Objects;
722→
723→	if (!rotated_pnt)
724→	{
725→		g3_rotate_point(&objpnt, &obj->pos);
726→		rotated_pnt = &objpnt.p3_vec;
727→	}
728→
729→	//First, get static light for this segment
730→	light = Segment2s[obj->segnum].static_light;
731→
732→	//return light;
733→	//Now, maybe return different value to smooth transitions
734→
735→	if (!reset_lighting_hack && object_sig[objnum] == obj->signature)
736→	{
737→		fix delta_light, frame_delta;
738→
739→		delta_light = light - object_light[objnum];
740→		frame_delta = fixmul(LIGHT_RATE, FrameTime);
741→		if (abs(delta_light) <= frame_delta)
742→			object_light[objnum] = light;		//we've hit the goal
743→		else
744→			if (delta_light < 0)
745→				light = object_light[objnum] -= frame_delta;
746→			else
747→				light = object_light[objnum] += frame_delta;
748→	}
749→	else //new object, initialize
750→	{
751→		object_sig[objnum] = obj->signature;
752→		object_light[objnum] = light;
753→	}
754→
755→	//Next, add in headlight on this object
756→
757→	if (CurrentLogicVersion >= LogicVer::FULL_1_0)
758→		light += compute_headlight_light_on_object(obj);
759→	else
760→		light += compute_headlight_light(rotated_pnt, f1_0);
761→
762→	//Finally, add in dynamic light for this segment
763→
764→	light += compute_seg_dynamic_light(obj->segnum);
765→
766→	return light;
767→#endif
768→}
769→
770→// ---------------------------------------------------------
771→
772→//[ISB] this is needed for eventual Descent 2 Demo support. 
773→ //Compute the lighting from the headlight for a given vertex on a face.
774→ //Takes:
775→ //  point - the 3d coords of the point
776→ //  face_light - a scale factor derived from the surface normal of the face
777→ //If no surface normal effect is wanted, pass F1_0 for face_light
778→fix compute_headlight_light(vms_vector* point, fix face_light)
779→{
780→#ifdef USE_OX_BRIDGE
781→	return cd_ox_compute_headlight_light_d2(
782→		point->x, point->y, point->z,
783→		face_light, Beam_brightness,
784→		Players[Player_num].flags, Players[Player_num].energy,
785→		(Viewer == &Objects[Players[Player_num].objnum]) ? 1 : 0);
786→#else
787→	fix light;
788→	int use_beam = 0;		//flag for beam effect
789→
790→	light = Beam_brightness;
791→
792→	if ((Players[Player_num].flags & PLAYER_FLAGS_HEADLIGHT) && (Players[Player_num].flags & PLAYER_FLAGS_HEADLIGHT_ON) && Viewer == &Objects[Players[Player_num].objnum] && Players[Player_num].energy > 0)
793→	{
794→		light *= HEADLIGHT_BOOST_SCALE;
795→		use_beam = 1;	//give us beam effect
796→	}
797→
798→	if (light) //if no beam, don't bother with the rest of this
799→	{
800→		fix point_dist;
801→
802→		point_dist = vm_vec_mag_quick(point);
803→
804→		if (point_dist >= MAX_DIST)
805→
806→			light = 0;
807→
808→		else
809→		{
810→			fix dist_scale, face_scale;
811→
812→			dist_scale = (MAX_DIST - point_dist) >> MAX_DIST_LOG;
813→			light = fixmul(light, dist_scale);
814→
815→			if (face_light < 0)
816→				face_light = 0;
817→
818→			face_scale = f1_0 / 4 + face_light / 2;
819→			light = fixmul(light, face_scale);
820→
821→			if (use_beam)
822→			{
823→				fix beam_scale;
824→
825→				if (face_light > f1_0 * 3 / 4 && point->z > i2f(12))
826→				{
827→					beam_scale = fixdiv(point->z, point_dist);
828→					beam_scale = fixmul(beam_scale, beam_scale);	//square it
829→					light = fixmul(light, beam_scale);
830→				}
831→			}
832→		}
833→	}
834→
835→	return light;
836→#endif
837→}
