    v_result = caml_callback2(*g_find_min_max, Val_int(model_num), Val_int(submodel_num));

    out_min[0] = Int_val(Field(v_result, 0));
    out_min[1] = Int_val(Field(v_result, 1));
    out_min[2] = Int_val(Field(v_result, 2));
    out_max[0] = Int_val(Field(v_result, 3));
    out_max[1] = Int_val(Field(v_result, 4));
    out_max[2] = Int_val(Field(v_result, 5));
    CAMLreturn0;
}

/* C entry point: pack vertex data, call OCaml init_points, unpack results.
   Input array: [has_box_size, box_x, box_y, box_z, nverts, vp[0].x,y,z, ...]
   Output array: [n_morphing_points, times[0], vecs[0].x,y,z, deltas[0].x,y,z, ...] */
void cd_ox_init_points(int nverts,
    int has_box_size, int32_t box_x, int32_t box_y, int32_t box_z,
    int32_t* n_morphing_points,
    int32_t* morph_times,
    int32_t* morph_vecs,
    int32_t* morph_deltas,
    int32_t* final_verts)
{
    cd_ox_require_ready("cd_ox_init_points");
    if (!g_init_points) return;

    CAMLparam0();
    CAMLlocal2(v_input, v_result);

    int arr_len = 5 + nverts * 3;
    v_input = caml_alloc(arr_len, 0);
    Store_field(v_input, 0, Val_long(has_box_size));
    Store_field(v_input, 1, Val_long(box_x));
    Store_field(v_input, 2, Val_long(box_y));
    Store_field(v_input, 3, Val_long(box_z));
    Store_field(v_input, 4, Val_long(nverts));

    for (int v = 0; v < nverts; v++) {
        int base = 5 + v * 3;
        Store_field(v_input, base + 0, Val_long(final_verts[v * 3 + 0]));
        Store_field(v_input, base + 1, Val_long(final_verts[v * 3 + 1]));
        Store_field(v_input, base + 2, Val_long(final_verts[v * 3 + 2]));
    }

    v_result = caml_callback(*g_init_points, v_input);

    *n_morphing_points = Long_val(Field(v_result, 0));
    for (int v = 0; v < nverts; v++) {
        int obase = 1 + v * 7;
        morph_times[v] = Long_val(Field(v_result, obase + 0));
        morph_vecs[v * 3 + 0] = Long_val(Field(v_result, obase + 1));
        morph_vecs[v * 3 + 1] = Long_val(Field(v_result, obase + 2));
        morph_vecs[v * 3 + 2] = Long_val(Field(v_result, obase + 3));
        morph_deltas[v * 3 + 0] = Long_val(Field(v_result, obase + 4));
        morph_deltas[v * 3 + 1] = Long_val(Field(v_result, obase + 5));
        morph_deltas[v * 3 + 2] = Long_val(Field(v_result, obase + 6));
    }

    CAMLreturn0;
}

/* C entry point: pack morph data, call OCaml update_points, unpack results.
   Input array: [frame_time, nverts, n_morphing_points,
     morph_times[0], vecs[0].x,y,z, deltas[0].x,y,z, final[0].x,y,z, ...]
   Output array: [n_morphing_points, times[0], vecs[0].x,y,z, ...] */
void cd_ox_update_points(int morph_slot, int submodel_num,
    int32_t frame_time,
    int nverts, int start_index,
    int32_t* n_morphing_points,
    int32_t* morph_times,
    int32_t* morph_vecs,
    int32_t* morph_deltas,
    int32_t* final_verts)
{
    cd_ox_require_ready("cd_ox_update_points");
    if (!g_update_points) return;

    CAMLparam0();
    CAMLlocal2(v_input, v_result);

    int arr_len = 3 + nverts * 10;
    v_input = caml_alloc(arr_len, 0);
    Store_field(v_input, 0, Val_long(frame_time));
    Store_field(v_input, 1, Val_long(nverts));
    Store_field(v_input, 2, Val_long(*n_morphing_points));

    for (int v = 0; v < nverts; v++) {
        int base = 3 + v * 10;
        Store_field(v_input, base + 0, Val_long(morph_times[v]));
        Store_field(v_input, base + 1, Val_long(morph_vecs[v * 3 + 0]));
        Store_field(v_input, base + 2, Val_long(morph_vecs[v * 3 + 1]));
        Store_field(v_input, base + 3, Val_long(morph_vecs[v * 3 + 2]));
        Store_field(v_input, base + 4, Val_long(morph_deltas[v * 3 + 0]));
        Store_field(v_input, base + 5, Val_long(morph_deltas[v * 3 + 1]));
        Store_field(v_input, base + 6, Val_long(morph_deltas[v * 3 + 2]));
        Store_field(v_input, base + 7, Val_long(final_verts[v * 3 + 0]));
        Store_field(v_input, base + 8, Val_long(final_verts[v * 3 + 1]));
        Store_field(v_input, base + 9, Val_long(final_verts[v * 3 + 2]));
    }

    v_result = caml_callback(*g_update_points, v_input);

    *n_morphing_points = Long_val(Field(v_result, 0));
    for (int v = 0; v < nverts; v++) {
        int obase = 1 + v * 4;
        morph_times[v] = Long_val(Field(v_result, obase + 0));
        morph_vecs[v * 3 + 0] = Long_val(Field(v_result, obase + 1));
        morph_vecs[v * 3 + 1] = Long_val(Field(v_result, obase + 2));
        morph_vecs[v * 3 + 2] = Long_val(Field(v_result, obase + 3));
    }

    CAMLreturn0;
}

/* morph_start effect registration */
void cd_ox_register_morph_start_effects(
    cd_effect_morph_start_setup_fn setup_fn,
    cd_effect_morph_start_commit_fn commit_fn)
{
    g_effect_morph_start_setup = setup_fn;
    g_effect_morph_start_commit = commit_fn;
}

/* C external: OCaml calls this to find free morph slot + read object state.
   Returns int array [free_slot, signature, render_type, control_type,
                      movement_type, model_num, submodel0_start_index] */
CAMLprim value cd_ox_effect_morph_start_setup(value v_objnum)
{
    CAMLparam1(v_objnum);
    CAMLlocal1(v_arr);

    int32_t out_data[7];
    memset(out_data, 0, sizeof(out_data));
    out_data[0] = -1; /* default: no free slot */

    if (g_effect_morph_start_setup)
        g_effect_morph_start_setup(Int_val(v_objnum), out_data);

    v_arr = caml_alloc(7, 0);
    for (int i = 0; i < 7; i++)
        Store_field(v_arr, i, Val_long(out_data[i]));

    /* Stash objnum so commit handler knows which object to modify */
    g_morph_start_objnum = Int_val(v_objnum);

    CAMLreturn(v_arr);
}

/* C external: OCaml calls this to apply all morph_start state changes.
   Input int array: [slot_idx, start_index, nverts, n_morphing_points,
                     per-vertex: morph_time, vec.x,y,z, delta.x,y,z ...] */
CAMLprim value cd_ox_effect_morph_start_commit(value v_data)
{
    CAMLparam1(v_data);

    int data_len = Wosize_val(v_data);
    int32_t* data = (int32_t*)malloc(data_len * sizeof(int32_t));
    for (int i = 0; i < data_len; i++)
        data[i] = Long_val(Field(v_data, i));

    if (g_effect_morph_start_commit)
        g_effect_morph_start_commit(g_morph_start_objnum, data, data_len);

    free(data);
    CAMLreturn(Val_unit);
}

