/* OCaml external: fetch obj allocate data as int array */
CAMLprim value cd_ox_effect_fetch_obj_allocate_data(value v_unit)
{
    CAMLparam1(v_unit);
    CAMLlocal1(v_result);
    (void)v_unit;

